import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { getProduits } from '../services/stockApi';
import { Search, ChevronRight, Package } from 'lucide-react';
import Spinner from '../components/Spinner';
import toast from 'react-hot-toast';

export default function Products() {
  const [produits, setProduits] = useState([]);
  const [loading,  setLoading]  = useState(true);
  const [search,   setSearch]   = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    getProduits()
      .then(r => setProduits(r.data))
      .catch(() => toast.error('Erreur chargement'))
      .finally(() => setLoading(false));
  }, []);

  const filtered = produits.filter(p =>
    p.name.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="page">
      <div className="page-header">
        <div>
          <h2>Produits</h2>
          <p>{produits.length} produit(s) référencé(s)</p>
        </div>
      </div>

      <div className="toolbar">
        <div className="search-box">
          <Search />
          <input placeholder="Rechercher un produit…"
                 value={search} onChange={e => setSearch(e.target.value)} />
        </div>
      </div>

      {loading ? <Spinner /> : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: 16 }}>
          {filtered.map(p => (
            <div
              key={p.id}
              className="card"
              style={{ cursor: 'pointer', transition: 'border 0.15s' }}
              onMouseEnter={e => e.currentTarget.style.borderColor = 'var(--accent)'}
              onMouseLeave={e => e.currentTarget.style.borderColor = 'var(--border)'}
              onClick={() => navigate(`/stock/${p.id}`)}
            >
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                  <div style={{ background: 'rgba(59,130,246,0.12)', color: 'var(--accent)',
                                borderRadius: 10, padding: 10, display: 'flex' }}>
                    <Package size={18} />
                  </div>
                  <div>
                    <div style={{ fontWeight: 600, fontSize: 14 }}>{p.name}</div>
                    <div style={{ color: 'var(--text-muted)', fontSize: 12, fontFamily: 'var(--mono)', marginTop: 2 }}>
                      {p.price?.toFixed(2)} €
                    </div>
                  </div>
                </div>
                <ChevronRight size={16} style={{ color: 'var(--text-muted)' }} />
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
